properties.valueHandler:
const selectedComponent = Utils.first(Vars.selectedComponents);
const currentType = Editor.getComponentStyle(Utils.first(Vars.selectedComponents), 'justify-content') ?? 'default';
const options = [
  { label: 'flex-start', value: 'flex-start' },
  { label: 'flex-end', value: 'flex-end' },
  { label: 'center', value: 'center' },
];
return [options, [[currentType]]];

properties.stateHandler:
const selectedComponent = Utils.first(Vars.selectedComponents);
let isDisabled = 'enabled';
if (selectedComponent?.styleHandlers?.['justify-content']) {
  isDisabled = 'disabled';
}
return isDisabled;

eventHandlers.changed:
const selectedComponent = Utils.first(Vars.selectedComponents);
const typeValue = EventData.value || 'default';
updateStyle(selectedComponent, 'justify-content', typeValue);

properties.checkboxHandler:
const parameter = 'justify-content';
let typeHandler = '';
const selectedComponent = Utils.first(Vars.selectedComponents);
typeHandler = selectedComponent?.styleHandlers?.['justify-content'] || '';
return [parameter, typeHandler];

properties.stateHandler:
const selectedComponent = Utils.first(Vars.selectedComponents);
let state = 'enabled';
if (selectedComponent?.styleHandlers && selectedComponent?.styleHandlers['gap']) {
  state = 'disabled';
}
return state;

properties.checkboxHandler:
const parameter = 'gap';
let heightHandler = '';
const selectedComponent = Utils.first(Vars.selectedComponents);
heightHandler = selectedComponent?.styleHandlers && selectedComponent?.styleHandlers['gap'] || '';
return [parameter, heightHandler];
